import { describe, it, expect } from "vitest";

// Types for our logic module
interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface Customer {
  yearsWithMHPCO: number;
}

interface DamageEntry {
  itemType: string;
  amount: number;
}

interface ProcessQuoteInput {
  items: Item[];
  customer: Customer;
  contractCount: number; // how many contracts before this one (0 = first)
}

interface ProcessClaimInput {
  policyItems: Item[];
  damages: DamageEntry[];
  previousPayouts: number; // total already paid out on this policy
  insuranceSum: number;
}

interface QuoteResult {
  premium: number;
}

interface ClaimResult {
  payout: number;
  remainingCap: number;
}

describe("Claim Office - Quote (Premium Calculation)", () => {
  it.todo("should return 5 G for an empty item list (only processing fee)");

  it.todo("should return 105 G for a single sword (100 base + 5 fee)");

  it.todo("should return 65 G for a single amulet (60 base + 5 fee)");

  it.todo("should return 85 G for a single staff (80 base + 5 fee)");

  it.todo("should return 45 G for a single potion (40 base + 5 fee)");

  it.todo("should return 30 G for a single rune (25 base + 5 fee)");

  it.todo("should return 30 G for a single moonstone (25 base + 5 fee)");

  it.todo("should return 55 G for 2 runes (50 base + 5 fee -- no block)");

  it.todo("should return 65 G for 3 runes (60 block + 5 fee)");

  it.todo("should return 105 G for 4 runes (100 base + 5 fee -- no block)");

  it.todo("should return 180 G for 7 runes (175 base + 5 fee -- no block)");

  it.todo("should return 80 G for 2 runes + 1 moonstone (75 base + 5 fee -- no block, different types)");

  it.todo("should return 125 G for 3 runes + 3 moonstones (120 base + 5 fee -- two separate blocks)");

  it.todo("should add 50% cursed surcharge to cursed item's base premium");

  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");

  it.todo("should NOT add high-enchantment surcharge for enchantment 4");

  it.todo("should apply both curse and high-enchantment surcharges when both apply");

  it.todo("should apply 20% loyalty discount for customers with >= 2 years");

  it.todo("should apply 10% first insurance surcharge");

  it.todo("should apply 15% follow-up contract discount for contracts after the first");

  it.todo("should apply item-specific modifiers (curse, high enchantment) to the affected item's base premium, not policy total");

  it.todo("should apply policy-wide modifiers (loyalty, first insurance, follow-up) to the sum of all item base premiums");

  it.todo("should add 5 G processing fee at the very end");

  it.todo("should round up final premium in MHPCO's favor (197.5 -> 198)");

  it.todo("should calculate premium as 165 G for newcomer with cursed sword (100 base + 50 curse + 10 first insurance + 5 fee)");

  it.todo("should calculate premium as 160 G for long-standing customer's second contract with cursed high-enchantment sword (100 base + 50 curse + 30 high-enchant - 20 loyalty + 10 first insurance - 15 follow-up + 5 fee)");
});

describe("Claim Office - Claim (Payout Calculation)", () => {
  it.todo("should return payout 400 G for a steel sword with damage 500 (500 - 100 deductible)");

  it.todo("should return payout 100 G for a rune with damage 200 (200 - 100 deductible -- no special clauses)");

  it.todo("should apply 100 G deductible per damaged item (sword 500 + amulet 300 -> 600 payout)");

  it.todo("should reimburse at 50% for items with enchantment >= 8 then apply deductible (dragon sword ench 8, damage 1000 -> 400 payout)");

  it.todo("should fully reimburse dragon-material items then apply deductible (dragon sword ench 5, damage 800 -> 700 payout)");

  it.todo("should apply 50% rule (wins over dragon material) for enchantment >= 8 on dragon material (ench 9, damage 1000 -> 400 payout)");

  it.todo("should apply only high-enchantment clause for steel sword with enchantment 9 (damage 1000 -> 400 payout)");

  it.todo("should apply 50% for enchantment 8 on dragon material (damage 1000 -> 400 payout)");

  it.todo("should compute insurance sum as sum of item insurance values");

  it.todo("should compute cap as 2x the insurance sum");

  it.todo("should cap payout at remaining cap (first claim 1500 on 1000 insurance -> 1400 payout, remaining cap 600)");

  it.todo("should reduce second claim payout to remaining cap (remaining 600 -> payout 600, remaining cap 0)");

  it.todo("should compute insurance sum correctly with block discount not affecting sum (sword + 3 runes -> 1750 insurance sum)");

  it.todo("should compute cap based on unmodified insurance value, not premium modifiers");

  it.todo("should round down final payout in MHPCO's favor (350.5 -> 350)");

  it.todo("should reject claim with more damages of a type than insured items (non-zero exit)");

  it.todo("should reject claim with damage to item not in policy (non-zero exit)");

  it.todo("should reject claim with damage amount -200 (non-zero exit)");
});

describe("Claim Office - CLI", () => {
  it.todo("should exit with non-zero code for unknown item type in quote (e.g. broomstick)");

  it.todo("should process a full scenario with quote then claim from stdin and output results to stdout");
});

