import { describe, it, expect } from "vitest";
import { processQuote } from "./claim-office.js";

// Types for our logic module
interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface Customer {
  yearsWithMHPCO: number;
}

interface DamageEntry {
  itemType: string;
  amount: number;
}

interface ProcessQuoteInput {
  items: Item[];
  customer: Customer;
  contractCount: number; // how many contracts before this one (0 = first)
}

interface ProcessClaimInput {
  policyItems: Item[];
  damages: DamageEntry[];
  previousPayouts: number; // total already paid out on this policy
  insuranceSum: number;
}

interface QuoteResult {
  premium: number;
}

interface ClaimResult {
  payout: number;
  remainingCap: number;
}

describe("Claim Office - Quote (Premium Calculation)", () => {
  it("should return 5 G for an empty item list (only processing fee)", () => {
    const premium = processQuote({
      items: [],
      customer: { yearsWithMHPCO: 0 },
      contractCount: 0,
    });
    expect(premium).toBe(5);
  });

