export function processQuote(input: {
  items: { type: string; material?: string; enchantment?: number; cursed?: boolean }[];
  customer: { yearsWithMHPCO: number };
  contractCount: number;
}): number {
  if (input.items.length === 0) return PROCESSING_FEE;
  const mainItems = input.items.filter((item) => !COMPONENT_TYPES.has(item.type));
  const components = input.items.filter((item) => COMPONENT_TYPES.has(item.type));
  const mainBase = mainItems.reduce(
    (sum, item) => sum + BASE_PREMIUMS[item.type],
    0,
  );
  const componentBase = computeComponentBase(components);
  return mainBase + componentBase + PROCESSING_FEE;
}

